SELECT ?image ?imageDate ?rec ?recordDate ?county ?countyLabel
WHERE {
  ?county a goo:County ;
          rdfs:label ?countyLabel ;
          goo:locatedInState ?state .
  ?state a goo:State ;
         goo:statePostalCode "FL" .
  FILTER (CONTAINS(LCASE(STR(?countyLabel)), "levy"))
  ?rec a goo:CustomerOutageRecord ;
       goo:representsCounty ?county ;
       goo:recordDateTime ?recordDate .
  FILTER (?recordDate >= "2017-08-15T20:15:00Z"^^xsd:dateTime && ?recordDate < "2017-08-15T20:16:00Z"^^xsd:dateTime)
  ?image a goo:NTLImage ;
         goo:representsCounty ?county ;
         goo:acquisitionDateTime ?imageDate .
  FILTER (SUBSTR(STR(?imageDate), 1, 10) = SUBSTR(STR(?recordDate), 1, 10))
}
ORDER BY ?imageDate
LIMIT 10

