PREFIX schema:     <http://schema.org/>
PREFIX units:      <http://www.opengis.net/def/uom/OGC/1.0/>

SELECT ?county ?countyLabel ?rec ?date ?numOutages
WHERE {
  {
    SELECT ?county (MAX(?n) AS ?maxOutages)
    WHERE {
      ?r a goo:CustomerOutageRecord ;
         goo:representsCounty ?county ;
         goo:numberOfOutages ?n .
    }
    GROUP BY ?county
  }
  ?rec a goo:CustomerOutageRecord ;
       goo:representsCounty ?county ;
       goo:recordDateTime ?date ;
       goo:numberOfOutages ?numOutages .
  ?county a goo:County ;
          rdfs:label ?countyLabel .
  FILTER (?numOutages = ?maxOutages)
}
ORDER BY ?countyLabel ?date

