SELECT ?map ?image ?imageDate ?sensor ?sensorLabel ?county ?countyLabel
WHERE {
  ?county a goo:County ;
          rdfs:label ?countyLabel ;
          goo:locatedInState ?state .
  ?state a goo:State ;
         goo:statePostalCode "FL" .
  FILTER (CONTAINS(LCASE(STR(?countyLabel)), "lake"))
  ?image a goo:NTLImage ;
         goo:representsCounty ?county ;
         goo:acquisitionDateTime ?imageDate ;
         goo:fromSensor ?sensor ;
         goo:hasOutageMap ?map .
  ?map a goo:OutageMap .
  OPTIONAL { ?sensor rdfs:label ?sensorLabel . }
  FILTER (?imageDate >= "2024-03-01T00:00:00Z"^^xsd:dateTime && ?imageDate < "2024-04-01T00:00:00Z"^^xsd:dateTime)
  FILTER (CONTAINS(UCASE(STR(?sensor)), "VIIRS") || (BOUND(?sensorLabel) && CONTAINS(UCASE(STR(?sensorLabel)), "VIIRS")))
}
ORDER BY ?imageDate
LIMIT 10

