SELECT ?numCyclones ?event ?eventLabel (MAX(?wind) AS ?maxSustainedWindSpeed)
WHERE {
  {
    SELECT (COUNT(DISTINCT ?eventCount) AS ?numCyclones)
    WHERE {
      ?eventCount a goo:HurricaneEventRecord ;
                  goo:basin "AL" ;
                  goo:hasTrackRecord ?trackCount .
      ?trackCount goo:recordDateTime ?trackDate .
      FILTER (?trackDate >= "2024-10-06T00:00:00Z"^^xsd:dateTime && ?trackDate < "2024-10-07T00:00:00Z"^^xsd:dateTime)
    }
  }
  ?event a goo:HurricaneEventRecord ;
         goo:basin "AL" ;
         goo:hasTrackRecord ?track .
  OPTIONAL { ?event rdfs:label ?eventLabel . }
  ?track goo:recordDateTime ?trackDate ;
         goo:maxSustainedWindSpeed ?wind .
  FILTER (?trackDate >= "2024-10-06T00:00:00Z"^^xsd:dateTime && ?trackDate < "2024-10-07T00:00:00Z"^^xsd:dateTime)
}
GROUP BY ?numCyclones ?event ?eventLabel
ORDER BY DESC(?maxSustainedWindSpeed)
LIMIT 10

PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:       <http://example.org/resource#>
