PREFIX schema:     <http://schema.org/>
PREFIX units:      <http://www.opengis.net/def/uom/OGC/1.0/>

SELECT ?county ?countyLabel ?maxOutages ?hurricane ?hurricaneLabel
WHERE {
  {
    SELECT ?county (MAX(?numOutages) AS ?maxOutages)
    WHERE {
      ?county a goo:County ;
              rdfs:label ?countyLabel0 ;
              goo:locatedInState ?state0 .
      ?state0 a goo:State ;
              goo:statePostalCode "FL" .
      FILTER (CONTAINS(LCASE(STR(?countyLabel0)), "lee"))
      ?rec a goo:CustomerOutageRecord ;
           goo:representsCounty ?county ;
           goo:recordDateTime ?date ;
           goo:numberOfOutages ?numOutages .
      FILTER (?date >= "2022-09-28T00:00:00Z"^^xsd:dateTime && ?date < "2022-09-29T00:00:00Z"^^xsd:dateTime)
    }
    GROUP BY ?county
  }
  ?county rdfs:label ?countyLabel ;
          geosparql:hasGeometry/geosparql:asWKT ?countyWKT .
  OPTIONAL {
    ?hurricane a goo:HurricaneEventRecord ;
               goo:hasTrackRecord ?track .
    OPTIONAL { ?hurricane rdfs:label ?hurricaneLabel . }
    ?track goo:recordDateTime ?trackDate ;
           geosparql:hasGeometry/geosparql:asWKT ?trackWKT .
    FILTER (?trackDate >= "2022-09-28T00:00:00Z"^^xsd:dateTime && ?trackDate < "2022-09-29T00:00:00Z"^^xsd:dateTime)
    FILTER (geof:distance(?trackWKT, ?countyWKT, units:metre) <= 100000)
  }
}
LIMIT 10

