SELECT ?numTornadoRecords ?event ?eventStart ?efRating ?injuries ?eventCounty ?eventCountyLabel
WHERE {
  {
    SELECT (COUNT(DISTINCT ?eventCount) AS ?numTornadoRecords)
    WHERE {
      ?targetCounty a goo:County ;
                    rdfs:label ?targetCountyLabel ;
                    goo:locatedInState ?targetState .
      ?targetState a goo:State ;
                   goo:statePostalCode "OK" .
      FILTER (CONTAINS(LCASE(STR(?targetCountyLabel)), "cleveland"))
      ?eventCount a goo:TornadoEventRecord ;
                  goo:occurredInCounty ?eventCountyCount ;
                  goo:eventStartTime ?eventStartCount .
      FILTER (?eventStartCount >= "2013-05-20T00:00:00Z"^^xsd:dateTime && ?eventStartCount < "2013-05-21T00:00:00Z"^^xsd:dateTime)
      FILTER (?eventCountyCount = ?targetCounty || EXISTS { ?eventCountyCount goo:neighboringCounties ?targetCounty } || EXISTS { ?targetCounty goo:neighboringCounties ?eventCountyCount })
    }
  }
  ?targetCounty a goo:County ;
                rdfs:label ?targetCountyLabel ;
                goo:locatedInState ?targetState .
  ?targetState a goo:State ;
               goo:statePostalCode "OK" .
  FILTER (CONTAINS(LCASE(STR(?targetCountyLabel)), "cleveland"))
  ?event a goo:TornadoEventRecord ;
         goo:occurredInCounty ?eventCounty ;
         goo:eventStartTime ?eventStart .
  ?eventCounty rdfs:label ?eventCountyLabel .
  OPTIONAL { ?event goo:torFScale ?efRating . }
  OPTIONAL { ?event goo:injuriesDirect ?injuries . }
  FILTER (?eventStart >= "2013-05-20T00:00:00Z"^^xsd:dateTime && ?eventStart < "2013-05-21T00:00:00Z"^^xsd:dateTime)
  FILTER (?eventCounty = ?targetCounty || EXISTS { ?eventCounty goo:neighboringCounties ?targetCounty } || EXISTS { ?targetCounty goo:neighboringCounties ?eventCounty })
}
ORDER BY ?eventStart
LIMIT 10

PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
