SELECT ?numTornadoRecords ?event ?eventStart ?efRating ?injuries
WHERE {
  ?targetCounty a goo:County ;
                rdfs:label ?targetCountyLabel ;
                goo:locatedInState ?targetState ;
                geosparql:hasGeometry/geosparql:asWKT ?targetWKT .
  ?targetState a goo:State ;
               goo:statePostalCode "OK" .
  FILTER (CONTAINS(LCASE(STR(?targetCountyLabel)), "cleveland"))
  {
    SELECT ?targetCounty (COUNT(DISTINCT ?eventCount) AS ?numTornadoRecords)
    WHERE {
      ?targetCounty geosparql:hasGeometry/geosparql:asWKT ?targetWKT2 .
      ?eventCount a goo:TornadoEventRecord ;
                  goo:eventStartTime ?eventStartCount ;
                  geosparql:hasGeometry/geosparql:asWKT ?eventWKT2 .
      FILTER (?eventStartCount >= "2013-05-20T00:00:00Z"^^xsd:dateTime && ?eventStartCount < "2013-05-21T00:00:00Z"^^xsd:dateTime)
      FILTER (geof:distance(?eventWKT2, ?targetWKT2, units:metre) <= 50000)
    }
    GROUP BY ?targetCounty
  }
  ?event a goo:TornadoEventRecord ;
         goo:eventStartTime ?eventStart ;
         geosparql:hasGeometry/geosparql:asWKT ?eventWKT .
  OPTIONAL { ?event goo:torFScale ?efRating . }
