SELECT ?state ?stateLabel ?events2020 ?events2010 (?events2020 - ?events2010 AS ?eventCountDifference)
WHERE {
  ?state a goo:State ;
         rdfs:label ?stateLabel .
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?event2020) AS ?events2020Raw)
    WHERE {
      ?event2020 a goo:StormEventRecord ;
                 goo:occurredInState ?state ;
                 goo:eventStartTime ?date2020 .
      FILTER (?date2020 >= "2020-01-01T00:00:00Z"^^xsd:dateTime && ?date2020 < "2021-01-01T00:00:00Z"^^xsd:dateTime)
    }
    GROUP BY ?state
  }
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?event2010) AS ?events2010Raw)
    WHERE {
      ?event2010 a goo:StormEventRecord ;
                 goo:occurredInState ?state ;
                 goo:eventStartTime ?date2010 .
      FILTER (?date2010 >= "2010-01-01T00:00:00Z"^^xsd:dateTime && ?date2010 < "2011-01-01T00:00:00Z"^^xsd:dateTime)
    }
    GROUP BY ?state
  }
  BIND(COALESCE(?events2020Raw, 0) AS ?events2020)
  BIND(COALESCE(?events2010Raw, 0) AS ?events2010)
}
ORDER BY DESC(?eventCountDifference)

