SELECT ?numHurricanes ?hurricane ?hurricaneLabel ?landfallTime ?maxSustainedWindSpeed
WHERE {
  ?state a goo:State ;
         goo:statePostalCode "LA" ;
         geosparql:hasGeometry/geosparql:asWKT ?stateWKT .
  {
    SELECT ?state (COUNT(DISTINCT ?hurricaneCount) AS ?numHurricanes)
    WHERE {
      ?state geosparql:hasGeometry/geosparql:asWKT ?stateWKTCount .
      ?hurricaneCount a goo:HurricaneEventRecord ;
                      goo:hasTrackRecord ?trackCount .
      ?trackCount goo:recordDateTime ?trackDateCount ;
                  geosparql:hasGeometry/geosparql:asWKT ?trackWKTCount .
      FILTER (SUBSTR(STR(?trackDateCount), 6, 2) = "08")
      FILTER (geof:sfWithin(?trackWKTCount, ?stateWKTCount))
    }
    GROUP BY ?state
  }
  ?hurricane a goo:HurricaneEventRecord ;
             goo:hasTrackRecord ?track .
  OPTIONAL { ?hurricane rdfs:label ?hurricaneLabel . }
  ?track goo:recordDateTime ?landfallTime ;
         goo:maxSustainedWindSpeed ?maxSustainedWindSpeed ;
         geosparql:hasGeometry/geosparql:asWKT ?trackWKT .
  FILTER (SUBSTR(STR(?landfallTime), 6, 2) = "08")
  FILTER (geof:sfWithin(?trackWKT, ?stateWKT))
}
