SELECT ?state ?stateLabel ?tornadoCount ?hurricaneCount ?thunderstormCount ?wildfireCount ?eventRatio
WHERE {
  VALUES ?stateCode { "FL" "CA" }
  ?state a goo:State ;
         goo:statePostalCode ?stateCode ;
         rdfs:label ?stateLabel .
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?tornado) AS ?tornadoRaw)
    WHERE {
      ?tornado a goo:StormEventRecord ;
               goo:occurredInState ?state ;
               goo:stormEventType ?type .
      FILTER (CONTAINS(UCASE(STR(?type)), "TORNADO"))
    }
    GROUP BY ?state
  }
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?hurricane) AS ?hurricaneRaw)
    WHERE {
      ?state geosparql:hasGeometry/geosparql:asWKT ?stateWKT .
      ?hurricane a goo:HurricaneEventRecord ;
                 goo:hasTrackRecord ?track .
      ?track geosparql:hasGeometry/geosparql:asWKT ?trackWKT .
      FILTER (geof:sfWithin(?trackWKT, ?stateWKT))
    }
    GROUP BY ?state
  }
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?thunderstorm) AS ?thunderstormRaw)
    WHERE {
      ?thunderstorm a goo:StormEventRecord ;
                    goo:occurredInState ?state ;
                    goo:stormEventType ?type .
      FILTER (CONTAINS(UCASE(STR(?type)), "THUNDERSTORM"))
    }
    GROUP BY ?state
  }
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?wildfire) AS ?wildfireRaw)
    WHERE {
      ?wildfire a goo:StormEventRecord ;
                goo:occurredInState ?state ;
                goo:stormEventType ?type .
      FILTER (CONTAINS(UCASE(STR(?type)), "WILDFIRE") || CONTAINS(UCASE(STR(?type)), "WILD FIRE"))
    }
    GROUP BY ?state
  }
  BIND(COALESCE(?tornadoRaw, 0) AS ?tornadoCount)
  BIND(COALESCE(?hurricaneRaw, 0) AS ?hurricaneCount)
  BIND(COALESCE(?thunderstormRaw, 0) AS ?thunderstormCount)
  BIND(COALESCE(?wildfireRaw, 0) AS ?wildfireCount)
  BIND(CONCAT(STR(?tornadoCount), ":", STR(?hurricaneCount), ":", STR(?thunderstormCount), ":", STR(?wildfireCount)) AS ?eventRatio)
}
ORDER BY ?stateLabel

