PREFIX geof:       <http://www.opengis.net/def/function/geosparql/>
PREFIX geo:        <http://www.w3.org/2003/01/geo/wgs84_pos#>
PREFIX xsd:        <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:       <http://www.w3.org/2000/01/rdf-schema#>
PREFIX schema:     <http://schema.org/>
PREFIX units:      <http://www.opengis.net/def/uom/OGC/1.0/>

SELECT ?county ?countyLabel ?socioeconomicScore (COUNT(DISTINCT ?event) AS ?windEventCount)
WHERE {
  ?state a goo:State ;
         goo:statePostalCode "FL" .
  ?county a goo:County ;
          rdfs:label ?countyLabel ;
          goo:locatedInState ?state .
  ?svi a goo:SVIRecord ;
       goo:representsCounty ?county ;
       goo:sviYear 2022 ;
       goo:sviSocioeconomicTheme ?socioeconomicScore .
  FILTER (?socioeconomicScore >= 0.8)
  ?event a goo:StormEventRecord ;
         goo:occurredInCounty ?county ;
         goo:stormEventType ?eventType ;
         goo:eventStartTime ?eventStart .
  FILTER (?eventStart >= "2022-01-01T00:00:00Z"^^xsd:dateTime && ?eventStart < "2023-01-01T00:00:00Z"^^xsd:dateTime)
  FILTER (CONTAINS(UCASE(STR(?eventType)), "WIND"))
}
GROUP BY ?county ?countyLabel ?socioeconomicScore
HAVING (COUNT(DISTINCT ?event) >= 12)
ORDER BY DESC(?windEventCount) DESC(?socioeconomicScore)
LIMIT 10

PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:       <http://example.org/resource#>
PREFIX geosparql: <http://www.opengis.net/ont/geosparql#>
PREFIX geof:       <http://www.opengis.net/def/function/geosparql/>
PREFIX geo:        <http://www.w3.org/2003/01/geo/wgs84_pos#>
PREFIX xsd:        <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:       <http://www.w3.org/2000/01/rdf-schema#>
PREFIX schema:     <http://schema.org/>
PREFIX units:      <http://www.opengis.net/def/uom/OGC/1.0/>

SELECT ?county ?countyLabel ?latestSVIYear ?socioeconomicScore (COUNT(DISTINCT ?event) AS ?windEventCount)
WHERE {
  ?state a goo:State ;
         goo:statePostalCode "FL" .
  ?county a goo:County ;
          rdfs:label ?countyLabel ;
          goo:locatedInState ?state .
  {
    SELECT ?county (MAX(?year) AS ?latestSVIYear)
    WHERE {
      ?sviLatest a goo:SVIRecord ;
                 goo:representsCounty ?county ;
                 goo:sviYear ?year .
    }
    GROUP BY ?county
  }
  ?svi a goo:SVIRecord ;
       goo:representsCounty ?county ;
       goo:sviYear ?latestSVIYear ;
       goo:sviSocioeconomicTheme ?socioeconomicScore .
  FILTER (?socioeconomicScore >= 0.8)
  ?event a goo:StormEventRecord ;
         goo:occurredInCounty ?county ;
         goo:stormEventType ?eventType ;
         goo:eventStartTime ?eventStart .
  FILTER (SUBSTR(STR(?eventStart), 1, 4) = STR(?latestSVIYear))
  FILTER (CONTAINS(UCASE(STR(?eventType)), "WIND"))
}
GROUP BY ?county ?countyLabel ?latestSVIYear ?socioeconomicScore
HAVING (COUNT(DISTINCT ?event) >= 10 && COUNT(DISTINCT ?event) <= 14)
ORDER BY DESC(?windEventCount) DESC(?socioeconomicScore)
LIMIT 10
